<section class="eco-card"><h1>Flows</h1></section>
<?php foreach ($flows as $flow): ?><section class="eco-card"><h3><?= e((string)$flow['name']) ?> (<?= e((string)$flow['flow_key']) ?>)</h3><p><?= e((string)$flow['target_type']) ?> - <?= e((string)$flow['is_active']) ?></p><table class="eco-table"><thead><tr><th>Step</th><th>Action</th><th>Required</th><th>Active</th></tr></thead><tbody><?php foreach (($flow['steps'] ?? []) as $step): ?><tr><td><?= e((string)$step['name']) ?></td><td><?= e((string)$step['action_type']) ?></td><td><?= e((string)$step['is_required']) ?></td><td><?= e((string)$step['is_active']) ?></td></tr><?php endforeach; ?></tbody></table></section><?php endforeach; ?>
